// src/pages/StudentDashboard.jsx - COMPLETE FIXED VERSION
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { 
  Loader2, 
  Calendar, 
  BookOpen, 
  TrendingUp, 
  Clock, 
  Award,
  CheckCircle,
  AlertCircle,
  RefreshCw,
  User,
  Mail,
  Phone,
  GraduationCap
} from 'lucide-react';
import ChatbotInterface from '../components/ChatbotInterface';

// ✅ Create axios instance with credentials for all API calls
const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || 'http://localhost:65000',
  withCredentials: true,
  headers: {
    'Content-Type': 'application/json'
  }
});

const StudentDashboard = () => {
  const [payload, setPayload] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showAllSemesters, setShowAllSemesters] = useState(false);
  const [activeTab, setActiveTab] = useState('overview');
  const [chatbotReady, setChatbotReady] = useState(false);

  useEffect(() => {
    loadDashboard();
    // Check chatbot status after a delay
    const timer = setTimeout(() => {
      setChatbotReady(true);
    }, 1000);
    return () => clearTimeout(timer);
  }, []);

  const loadDashboard = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await api.get('/api/students/getStudentDashboard');
      setPayload(res.data);
      
      // ✅ Store student info for chatbot in localStorage
      if (res.data.student) {
        const studentData = {
          _id: res.data.student._id,
          studentId: res.data.student.studentId,
          firstName: res.data.student.name?.firstName || '',
          lastName: res.data.student.name?.lastName || '',
          fullName: res.data.student.name?.fullName || '',
          universityEmail: res.data.student.universityEmail,
          role: 'student',
          department: res.data.student.department,
          section: res.data.student.section,
          degreeLevel: res.data.student.degreeLevel,
          profilePic: res.data.student.photoPath || null
        };
        
        localStorage.setItem('userInfo', JSON.stringify(studentData));
        console.log('Student data stored for chatbot:', studentData);
      }
    } catch (err) {
      console.error('Dashboard load error:', err);
      setError(err.response?.data?.message || 'Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  const getAttendanceColor = (percentage) => {
    if (percentage >= 75) return '#10B981';
    if (percentage >= 50) return '#F59E0B';
    return '#EF4444';
  };

  const getGradeColor = (grade) => {
    if (!grade) return '#6B7280';
    if (['A+', 'A', 'A-'].includes(grade)) return '#10B981';
    if (['B+', 'B', 'B-'].includes(grade)) return '#3B82F6';
    if (['C+', 'C', 'C-'].includes(grade)) return '#F59E0B';
    if (['D+', 'D', 'D-'].includes(grade)) return '#F97316';
    return '#EF4444';
  };

  const handleChatbotMessage = (message) => {
    console.log('Chatbot message received:', message);
    // You can add logic here to handle chatbot-initiated messages
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-gray-50">
        <div className="text-center">
          <Loader2 className="w-12 h-12 animate-spin text-blue-600 mx-auto mb-4" />
          <p className="text-gray-600">Loading your dashboard...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-white rounded-xl shadow-lg p-8 text-center">
          <AlertCircle className="w-16 h-16 text-red-500 mx-auto mb-4" />
          <h2 className="text-2xl font-bold text-gray-800 mb-2">Error Loading Dashboard</h2>
          <p className="text-gray-600 mb-6">{error}</p>
          <div className="flex gap-4 justify-center">
            <button
              onClick={loadDashboard}
              className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition flex items-center gap-2"
            >
              <RefreshCw className="w-4 h-4" />
              Try Again
            </button>
            <button
              onClick={() => window.location.href = '/login'}
              className="px-6 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition"
            >
              Go to Login
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (!payload) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <AlertCircle className="w-16 h-16 text-yellow-500 mx-auto mb-4" />
          <h2 className="text-xl font-semibold text-gray-800 mb-2">No Data Available</h2>
          <p className="text-gray-600 mb-4">Unable to load dashboard data.</p>
          <button
            onClick={loadDashboard}
            className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition"
          >
            Reload
          </button>
        </div>
      </div>
    );
  }

  const { student, academicProgress } = payload;
  const current = academicProgress.currentSemesterDetails || {};
  const percentProgress = Math.min(
    100,
    Math.round((academicProgress.totalCreditsEarned / Math.max(1, academicProgress.totalCreditsRequired)) * 100)
  );

  // Calculate attendance statistics
  const totalAttendance = current.courses?.reduce((sum, course) => {
    return sum + (course.attendancePercentage || 0);
  }, 0) || 0;
  
  const avgAttendance = current.courses?.length > 0 
    ? Math.round(totalAttendance / current.courses.length) 
    : 0;

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Chatbot Interface */}
      {chatbotReady && <ChatbotInterface onMessage={handleChatbotMessage} />}
      
      {/* Dashboard Header */}
      <header className="bg-gradient-to-r from-blue-600 to-indigo-700 text-white">
        <div className="container mx-auto px-4 py-6">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div className="flex items-center gap-4">
              <div className="relative">
                {student.photoPath ? (
                  <img
                    src={`${api.defaults.baseURL}/${student.photoPath}`}
                    alt={student.name?.fullName}
                    className="w-20 h-20 rounded-full border-4 border-white/30 object-cover"
                  />
                ) : (
                  <div className="w-20 h-20 rounded-full bg-white/20 flex items-center justify-center border-4 border-white/30">
                    <User className="w-10 h-10" />
                  </div>
                )}
                <div className="absolute -bottom-2 -right-2 bg-green-500 text-white rounded-full p-1">
                  <CheckCircle className="w-5 h-5" />
                </div>
              </div>
              
              <div>
                <h1 className="text-2xl md:text-3xl font-bold">{student.name?.fullName}</h1>
                <div className="flex flex-wrap items-center gap-3 mt-2">
                  <span className="bg-white/20 px-3 py-1 rounded-full text-sm font-medium">
                    {student.studentId}
                  </span>
                  <span className="bg-white/20 px-3 py-1 rounded-full text-sm font-medium">
                    {student.department} • {student.degreeLevel}
                  </span>
                  <span className="bg-white/20 px-3 py-1 rounded-full text-sm font-medium">
                    Section {student.section}
                  </span>
                </div>
                <div className="flex flex-wrap items-center gap-4 mt-3 text-sm opacity-90">
                  <span className="flex items-center gap-1">
                    <Mail className="w-4 h-4" />
                    {student.universityEmail}
                  </span>
                  {student.contactNumber && (
                    <span className="flex items-center gap-1">
                      <Phone className="w-4 h-4" />
                      {student.contactNumber}
                    </span>
                  )}
                </div>
              </div>
            </div>
            
            <div className="flex items-center gap-4">
              <button
                onClick={() => setShowAllSemesters(!showAllSemesters)}
                className="px-4 py-2 bg-white/20 hover:bg-white/30 rounded-lg transition flex items-center gap-2"
              >
                {showAllSemesters ? 'Hide' : 'Show'} Semesters
              </button>
              <button
                onClick={loadDashboard}
                className="px-4 py-2 bg-white text-blue-600 hover:bg-gray-100 rounded-lg transition flex items-center gap-2 font-medium"
              >
                <RefreshCw className="w-4 h-4" />
                Refresh
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Stats Bar */}
      <div className="container mx-auto px-4 -mt-6 mb-8">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="bg-white rounded-xl shadow-lg p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-gray-500 text-sm font-medium">CGPA</p>
                <p className="text-3xl font-bold text-gray-800 mt-1">
                  {academicProgress.cumulativeGPA || '0.00'}
                </p>
              </div>
              <div className="bg-blue-100 p-3 rounded-lg">
                <TrendingUp className="w-6 h-6 text-blue-600" />
              </div>
            </div>
            <p className="text-gray-500 text-sm mt-2">Out of 4.0</p>
          </div>
          
          <div className="bg-white rounded-xl shadow-lg p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-gray-500 text-sm font-medium">Credits</p>
                <p className="text-3xl font-bold text-gray-800 mt-1">
                  {academicProgress.totalCreditsEarned}/{academicProgress.totalCreditsRequired}
                </p>
              </div>
              <div className="bg-green-100 p-3 rounded-lg">
                <BookOpen className="w-6 h-6 text-green-600" />
              </div>
            </div>
            <p className="text-gray-500 text-sm mt-2">
              {percentProgress}% Complete
            </p>
          </div>
          
          <div className="bg-white rounded-xl shadow-lg p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-gray-500 text-sm font-medium">Attendance</p>
                <p className="text-3xl font-bold text-gray-800 mt-1">
                  {avgAttendance}%
                </p>
              </div>
              <div className="bg-orange-100 p-3 rounded-lg">
                <Clock className="w-6 h-6 text-orange-600" />
              </div>
            </div>
            <div className="mt-2">
              <div className="h-2 bg-gray-200 rounded-full overflow-hidden">
                <div 
                  className="h-full rounded-full transition-all duration-500"
                  style={{
                    width: `${avgAttendance}%`,
                    backgroundColor: getAttendanceColor(avgAttendance)
                  }}
                />
              </div>
            </div>
          </div>
          
          <div className="bg-white rounded-xl shadow-lg p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-gray-500 text-sm font-medium">Current Semester</p>
                <p className="text-3xl font-bold text-gray-800 mt-1">
                  {academicProgress.currentSemester || 'N/A'}
                </p>
              </div>
              <div className="bg-purple-100 p-3 rounded-lg">
                <Calendar className="w-6 h-6 text-purple-600" />
              </div>
            </div>
            <p className="text-gray-500 text-sm mt-2">Semester GPA: {current.semesterGPA || '-'}</p>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <main className="container mx-auto px-4 pb-12">
        {/* Tabs */}
        <div className="mb-8">
          <div className="border-b border-gray-200">
            <nav className="flex space-x-8">
              <button
                onClick={() => setActiveTab('overview')}
                className={`py-3 px-1 border-b-2 font-medium text-sm ${
                  activeTab === 'overview'
                    ? 'border-blue-500 text-blue-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                Overview
              </button>
              <button
                onClick={() => setActiveTab('courses')}
                className={`py-3 px-1 border-b-2 font-medium text-sm ${
                  activeTab === 'courses'
                    ? 'border-blue-500 text-blue-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                Courses
              </button>
              <button
                onClick={() => setActiveTab('progress')}
                className={`py-3 px-1 border-b-2 font-medium text-sm ${
                  activeTab === 'progress'
                    ? 'border-blue-500 text-blue-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                Progress
              </button>
            </nav>
          </div>
        </div>

        {/* Overview Tab */}
        {activeTab === 'overview' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Left Column - Progress */}
            <div className="lg:col-span-2 space-y-8">
              {/* Degree Progress Card */}
              <div className="bg-white rounded-xl shadow-lg p-6">
                <div className="flex items-center justify-between mb-6">
                  <h2 className="text-xl font-bold text-gray-800">Degree Progress</h2>
                  <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-sm font-medium">
                    {percentProgress}% Complete
                  </span>
                </div>
                
                <div className="space-y-4">
                  <div>
                    <div className="flex justify-between text-sm text-gray-600 mb-1">
                      <span>Credits Completed</span>
                      <span>{academicProgress.totalCreditsEarned}/{academicProgress.totalCreditsRequired}</span>
                    </div>
                    <div className="h-4 bg-gray-200 rounded-full overflow-hidden">
                      <div 
                        className="h-full bg-gradient-to-r from-blue-500 to-blue-600 rounded-full transition-all duration-1000"
                        style={{ width: `${percentProgress}%` }}
                      />
                    </div>
                  </div>
                  
                  <div className="grid grid-cols-2 gap-4 pt-4">
                    <div className="text-center p-4 bg-gray-50 rounded-lg">
                      <p className="text-sm text-gray-500">Semesters Completed</p>
                      <p className="text-2xl font-bold text-gray-800 mt-1">
                        {(academicProgress.allSemesters?.filter(s => s.status === 'Completed').length || 0)}
                      </p>
                    </div>
                    <div className="text-center p-4 bg-gray-50 rounded-lg">
                      <p className="text-sm text-gray-500">Active Courses</p>
                      <p className="text-2xl font-bold text-gray-800 mt-1">
                        {current.courses?.length || 0}
                      </p>
                    </div>
                  </div>
                </div>
              </div>

              {/* Current Semester Courses */}
              <div className="bg-white rounded-xl shadow-lg p-6">
                <div className="flex items-center justify-between mb-6">
                  <h2 className="text-xl font-bold text-gray-800">Current Semester Courses</h2>
                  <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full text-sm font-medium">
                    Semester {academicProgress.currentSemester}
                  </span>
                </div>
                
                <div className="space-y-4">
                  {(current.courses || []).length === 0 ? (
                    <div className="text-center py-8 text-gray-500">
                      <BookOpen className="w-12 h-12 mx-auto mb-4 text-gray-300" />
                      <p>No courses found for current semester</p>
                    </div>
                  ) : (
                    current.courses.map((course, index) => (
                      <div key={index} className="flex items-center justify-between p-4 border border-gray-200 rounded-lg hover:bg-gray-50 transition">
                        <div className="flex items-center gap-4">
                          <div className="w-12 h-12 bg-blue-50 rounded-lg flex items-center justify-center">
                            <BookOpen className="w-6 h-6 text-blue-600" />
                          </div>
                          <div>
                            <h3 className="font-semibold text-gray-800">{course.courseCode || 'N/A'}</h3>
                            <p className="text-sm text-gray-600">{course.courseName || 'Untitled Course'}</p>
                            <div className="flex items-center gap-3 mt-1">
                              <span className="text-xs px-2 py-1 bg-gray-100 rounded">
                                {course.creditsEarned || 0} Credits
                              </span>
                              <span className="text-xs px-2 py-1 bg-gray-100 rounded">
                                {course.attendancePercentage || 0}% Attendance
                              </span>
                            </div>
                          </div>
                        </div>
                        <div className="text-right">
                          <div className={`text-lg font-bold`} style={{ color: getGradeColor(course.grade) }}>
                            {course.grade || '-'}
                          </div>
                          <div className={`text-xs px-2 py-1 mt-1 rounded-full ${course.status === 'Enrolled' ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-700'}`}>
                            {course.status || 'N/A'}
                          </div>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>
            </div>

            {/* Right Column - Info */}
            <div className="space-y-8">
              {/* Student Info Card */}
              <div className="bg-white rounded-xl shadow-lg p-6">
                <h2 className="text-xl font-bold text-gray-800 mb-6">Student Information</h2>
                <div className="space-y-4">
                  <div>
                    <p className="text-sm text-gray-500">Enrollment Date</p>
                    <p className="font-medium">{student.enrollmentDate ? new Date(student.enrollmentDate).toLocaleDateString() : 'N/A'}</p>
                  </div>
                  <div>
                    <p className="text-sm text-gray-500">Scholarship</p>
                    <p className="font-medium">
                      {student.scholarship?.isApplicant 
                        ? `${student.scholarship.percentage}% Scholarship` 
                        : 'No Scholarship'}
                    </p>
                  </div>
                  <div>
                    <p className="text-sm text-gray-500">Current Status</p>
                    <span className="inline-flex items-center px-3 py-1 rounded-full text-sm font-medium bg-green-100 text-green-800">
                      <CheckCircle className="w-4 h-4 mr-1" />
                      Active
                    </span>
                  </div>
                </div>
              </div>

              {/* Quick Actions */}
              <div className="bg-white rounded-xl shadow-lg p-6">
                <h2 className="text-xl font-bold text-gray-800 mb-6">Quick Actions</h2>
                <div className="space-y-3">
                  <button className="w-full flex items-center justify-between p-3 border border-gray-200 rounded-lg hover:bg-blue-50 hover:border-blue-200 transition text-left">
                    <span className="font-medium text-gray-700">View Fee Statement</span>
                    <TrendingUp className="w-5 h-5 text-blue-600" />
                  </button>
                  <button className="w-full flex items-center justify-between p-3 border border-gray-200 rounded-lg hover:bg-green-50 hover:border-green-200 transition text-left">
                    <span className="font-medium text-gray-700">Download Transcript</span>
                    <Award className="w-5 h-5 text-green-600" />
                  </button>
                  <button className="w-full flex items-center justify-between p-3 border border-gray-200 rounded-lg hover:bg-purple-50 hover:border-purple-200 transition text-left">
                    <span className="font-medium text-gray-700">Update Profile</span>
                    <User className="w-5 h-5 text-purple-600" />
                  </button>
                  <button 
                    onClick={() => setShowAllSemesters(true)}
                    className="w-full flex items-center justify-between p-3 border border-gray-200 rounded-lg hover:bg-orange-50 hover:border-orange-200 transition text-left"
                  >
                    <span className="font-medium text-gray-700">View All Semesters</span>
                    <Calendar className="w-5 h-5 text-orange-600" />
                  </button>
                </div>
              </div>

              {/* Chatbot Info */}
              <div className="bg-gradient-to-r from-blue-500 to-indigo-600 rounded-xl shadow-lg p-6 text-white">
                <div className="flex items-center gap-3 mb-4">
                  <div className="w-10 h-10 bg-white/20 rounded-full flex items-center justify-center">
                    <GraduationCap className="w-6 h-6" />
                  </div>
                  <h2 className="text-xl font-bold">ERP Assistant</h2>
                </div>
                <p className="opacity-90 mb-4">
                  Need help with fees, attendance, or timetable? Ask our AI assistant!
                </p>
                <div className="text-sm opacity-80 space-y-2">
                  <p className="flex items-center gap-2">
                    <CheckCircle className="w-4 h-4" />
                    Check fee status
                  </p>
                  <p className="flex items-center gap-2">
                    <CheckCircle className="w-4 h-4" />
                    View attendance
                  </p>
                  <p className="flex items-center gap-2">
                    <CheckCircle className="w-4 h-4" />
                    Get timetable
                  </p>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Courses Tab */}
        {activeTab === 'courses' && (
          <div className="bg-white rounded-xl shadow-lg p-6">
            <h2 className="text-2xl font-bold text-gray-800 mb-6">Current Semester Courses</h2>
            
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="bg-gray-50">
                    <th className="py-3 px-4 text-left text-sm font-semibold text-gray-700">Course Code</th>
                    <th className="py-3 px-4 text-left text-sm font-semibold text-gray-700">Course Name</th>
                    <th className="py-3 px-4 text-left text-sm font-semibold text-gray-700">Credits</th>
                    <th className="py-3 px-4 text-left text-sm font-semibold text-gray-700">Attendance</th>
                    <th className="py-3 px-4 text-left text-sm font-semibold text-gray-700">Grade</th>
                    <th className="py-3 px-4 text-left text-sm font-semibold text-gray-700">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200">
                  {(current.courses || []).length === 0 ? (
                    <tr>
                      <td colSpan="6" className="py-8 text-center text-gray-500">
                        No courses found for current semester
                      </td>
                    </tr>
                  ) : (
                    current.courses.map((course, index) => (
                      <tr key={index} className="hover:bg-gray-50 transition">
                        <td className="py-4 px-4">
                          <span className="font-semibold text-blue-600">{course.courseCode || 'N/A'}</span>
                        </td>
                        <td className="py-4 px-4">
                          <div>
                            <p className="font-medium text-gray-800">{course.courseName || 'Untitled Course'}</p>
                          </div>
                        </td>
                        <td className="py-4 px-4">
                          <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-sm">
                            {course.creditsEarned || 0}
                          </span>
                        </td>
                        <td className="py-4 px-4">
                          <div className="flex items-center gap-3">
                            <div className="w-24 h-2 bg-gray-200 rounded-full overflow-hidden">
                              <div 
                                className="h-full rounded-full"
                                style={{
                                  width: `${course.attendancePercentage || 0}%`,
                                  backgroundColor: getAttendanceColor(course.attendancePercentage || 0)
                                }}
                              />
                            </div>
                            <span className="font-medium">{course.attendancePercentage || 0}%</span>
                          </div>
                        </td>
                        <td className="py-4 px-4">
                          <span 
                            className="px-3 py-1 rounded-full text-sm font-semibold"
                            style={{
                              backgroundColor: `${getGradeColor(course.grade)}20`,
                              color: getGradeColor(course.grade)
                            }}
                          >
                            {course.grade || '-'}
                          </span>
                        </td>
                        <td className="py-4 px-4">
                          <span className={`px-3 py-1 rounded-full text-sm font-medium ${
                            course.status === 'Enrolled' 
                              ? 'bg-green-100 text-green-800'
                              : course.status === 'Completed'
                              ? 'bg-blue-100 text-blue-800'
                              : 'bg-gray-100 text-gray-800'
                          }`}>
                            {course.status || 'N/A'}
                          </span>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Progress Tab */}
        {activeTab === 'progress' && (
          <div className="space-y-8">
            {/* Semester Progress Timeline */}
            <div className="bg-white rounded-xl shadow-lg p-6">
              <h2 className="text-2xl font-bold text-gray-800 mb-6">Academic Timeline</h2>
              <div className="relative">
                {/* Timeline line */}
                <div className="absolute left-0 md:left-1/2 h-full w-0.5 bg-blue-200 transform -translate-x-1/2"></div>
                
                {academicProgress.allSemesters?.map((semester, index) => (
                  <div key={index} className={`relative mb-8 ${index % 2 === 0 ? 'md:pr-1/2 md:pl-8' : 'md:pl-1/2 md:pr-8 md:text-right'}`}>
                    {/* Timeline dot */}
                    <div className="absolute left-0 md:left-1/2 w-4 h-4 bg-blue-500 rounded-full transform -translate-x-1/2"></div>
                    
                    <div className="bg-gray-50 rounded-lg p-6 ml-8 md:ml-0">
                      <div className="flex justify-between items-start mb-2">
                        <h3 className="text-lg font-bold text-gray-800">Semester {semester.semesterNumber}</h3>
                        <span className={`px-3 py-1 rounded-full text-sm font-medium ${
                          semester.status === 'Completed' 
                            ? 'bg-green-100 text-green-800'
                            : semester.status === 'Current'
                            ? 'bg-blue-100 text-blue-800'
                            : 'bg-yellow-100 text-yellow-800'
                        }`}>
                          {semester.status}
                        </span>
                      </div>
                      
                      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-4">
                        <div>
                          <p className="text-sm text-gray-500">GPA</p>
                          <p className="text-xl font-bold text-gray-800">{semester.semesterGPA || '-'}</p>
                        </div>
                        <div>
                          <p className="text-sm text-gray-500">Credits</p>
                          <p className="text-xl font-bold text-gray-800">
                            {semester.creditsEarned}/{semester.creditsAttempted}
                          </p>
                        </div>
                        <div>
                          <p className="text-sm text-gray-500">Courses</p>
                          <p className="text-xl font-bold text-gray-800">{semester.courses?.length || 0}</p>
                        </div>
                        <div>
                          <p className="text-sm text-gray-500">Period</p>
                          <p className="text-sm font-medium text-gray-800">
                            {semester.startDate ? new Date(semester.startDate).toLocaleDateString() : 'N/A'}
                          </p>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* GPA Chart */}
            <div className="bg-white rounded-xl shadow-lg p-6">
              <h2 className="text-2xl font-bold text-gray-800 mb-6">GPA Trend</h2>
              <div className="h-64 flex items-end gap-2">
                {academicProgress.allSemesters?.map((semester, index) => (
                  <div key={index} className="flex-1 flex flex-col items-center">
                    <div 
                      className="w-full bg-gradient-to-t from-blue-500 to-blue-600 rounded-t-lg transition-all duration-500"
                      style={{ 
                        height: `${(semester.semesterGPA || 0) * 25}%`,
                        maxHeight: '100%'
                      }}
                    />
                    <div className="mt-2 text-center">
                      <p className="text-sm font-medium text-gray-700">Sem {semester.semesterNumber}</p>
                      <p className="text-xs text-gray-500">{semester.semesterGPA || '0.00'}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* All Semesters Section */}
        {showAllSemesters && (
          <div className="mt-8 bg-white rounded-xl shadow-lg p-6">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-2xl font-bold text-gray-800">All Semesters</h2>
              <button
                onClick={() => setShowAllSemesters(false)}
                className="px-4 py-2 text-gray-600 hover:text-gray-800 transition"
              >
                Close
              </button>
            </div>
            
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="bg-gray-50">
                    <th className="py-3 px-4 text-left text-sm font-semibold text-gray-700">Semester</th>
                    <th className="py-3 px-4 text-left text-sm font-semibold text-gray-700">Status</th>
                    <th className="py-3 px-4 text-left text-sm font-semibold text-gray-700">GPA</th>
                    <th className="py-3 px-4 text-left text-sm font-semibold text-gray-700">Credits Earned</th>
                    <th className="py-3 px-4 text-left text-sm font-semibold text-gray-700">Period</th>
                    <th className="py-3 px-4 text-left text-sm font-semibold text-gray-700">Courses</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200">
                  {academicProgress.allSemesters?.map((semester, index) => (
                    <tr key={index} className="hover:bg-gray-50 transition">
                      <td className="py-4 px-4">
                        <span className="font-bold text-gray-800">Semester {semester.semesterNumber}</span>
                      </td>
                      <td className="py-4 px-4">
                        <span className={`px-3 py-1 rounded-full text-sm font-medium ${
                          semester.status === 'Completed' 
                            ? 'bg-green-100 text-green-800'
                            : semester.status === 'Current'
                            ? 'bg-blue-100 text-blue-800'
                            : 'bg-gray-100 text-gray-800'
                        }`}>
                          {semester.status}
                        </span>
                      </td>
                      <td className="py-4 px-4">
                        <span className="font-bold text-gray-800">{semester.semesterGPA || '-'}</span>
                      </td>
                      <td className="py-4 px-4">
                        <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-sm">
                          {semester.creditsEarned}/{semester.creditsAttempted}
                        </span>
                      </td>
                      <td className="py-4 px-4">
                        {semester.startDate ? (
                          <div className="text-sm">
                            <p>{new Date(semester.startDate).toLocaleDateString()}</p>
                            <p className="text-gray-500">to {new Date(semester.endDate).toLocaleDateString()}</p>
                          </div>
                        ) : (
                          <span className="text-gray-500">N/A</span>
                        )}
                      </td>
                      <td className="py-4 px-4">
                        <div className="space-y-1">
                          {semester.courses?.slice(0, 3).map((course, idx) => (
                            <div key={idx} className="text-sm">
                              <span className="font-medium">{course.courseCode}</span>
                              <span className="text-gray-500"> • {course.grade || 'No grade'}</span>
                            </div>
                          ))}
                          {semester.courses?.length > 3 && (
                            <div className="text-sm text-blue-600 font-medium">
                              +{semester.courses.length - 3} more courses
                            </div>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      {/* Footer */}
      <footer className="bg-gray-800 text-white py-8 mt-12">
        <div className="container mx-auto px-4">
          <div className="flex flex-col md:flex-row justify-between items-center">
            <div>
              <h3 className="text-xl font-bold mb-2">{student.department}</h3>
              <p className="text-gray-400">{student.degreeLevel} Program</p>
            </div>
            <div className="mt-4 md:mt-0">
              <p className="text-gray-400 text-sm">
                Last updated: {new Date().toLocaleDateString()} • 
                Student ID: {student.studentId}
              </p>
            </div>
            <div className="mt-4 md:mt-0">
              <button
                onClick={loadDashboard}
                className="px-4 py-2 bg-blue-600 hover:bg-blue-700 rounded-lg transition flex items-center gap-2"
              >
                <RefreshCw className="w-4 h-4" />
                Refresh Data
              </button>
            </div>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default StudentDashboard;
